+fn unique_temp_dir(label: &str) -> PathBuf {
+    let nanos = SystemTime::now()
+        .duration_since(UNIX_EPOCH)
+        .expect("clock before epoch")
+        .as_nanos();
+    env::temp_dir().join(format!(
+        "frankenengine-parser-gap-integ-{label}-{}-{nanos}",
+        process::id()
+    ))
